<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Account</title>
    <link rel="stylesheet" href="/css/styles.css">
    <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
    <script src="/js/domus-achievements.js"></script>
    <style>
        .loans-distribution-empty{min-height:180px;display:grid;place-items:center;padding:1.25rem;border:1px dashed #d8e0f2;border-radius:10px;background:#fff;color:#5d6b85;font-weight:600;text-align:center;line-height:1.45;}
        .loans-distribution-empty.is-loading{color:#7182a3;background:linear-gradient(90deg,#f7f9fc 0%,#eef3fb 50%,#f7f9fc 100%);background-size:200% 100%;animation:loans-loading 1.2s ease-in-out infinite;}
        .loans-distribution-card.is-empty .loans-distribution-layout{display:none;}
        .loans-distribution-card.is-loading .loans-distribution-layout{display:none;}
        @keyframes loans-loading{0%{background-position:200% 0;}100%{background-position:-200% 0;}}
    </style>
</head>
<body class="app-bg">
<main class="layout">
    <div id="sidebar-overlay" class="sidebar-overlay"></div>
    <aside id="sidebar" class="sidebar">
        <button id="sidebar-close" class="sidebar-close" type="button">x</button>
        <div class="sidebar-logo-wrap"><img class="sidebar-logo" src="/img/domus_logo.png" alt="Domus logo"></div>
        <section class="profile-card"><p id="sidebar-user-name" class="profile-name">Usuario</p><a id="sidebar-user-level" class="profile-level" href="/levels" style="display:none;color:inherit;text-decoration:none;">Cargando nivel...</a></section>
        <div id="sidebar-scroll" class="sidebar-scroll">
            <nav class="sidebar-nav">
                <a class="sidebar-link is-active" href="/account"><span class="nav-icon">&bull;</span><span>Inicio</span></a>
                <a class="sidebar-link" href="/account/users"><span class="nav-icon">&bull;</span><span>Usuarios</span></a>
                <a id="loans-link" class="sidebar-link" href="/account/loans"><span class="nav-icon">&bull;</span><span>Prestamos</span></a><a id="transfers-link" class="sidebar-link" href="/parent/transfers"><span class="nav-icon">&bull;</span><span>Dar dinero</span></a><a id="allowances-link" class="sidebar-link" href="/parent/allowances"><span class="nav-icon">&bull;</span><span>Mesadas</span></a><a id="savings-boxes-link" class="sidebar-link" href="/parent/savings-boxes"><span class="nav-icon">&bull;</span><span>Cajas de ahorro</span></a><a id="goals-link" class="sidebar-link" href="/child/goals"><span class="nav-icon">&bull;</span><span>Metas</span></a><a id="tasks-link" class="sidebar-link" href="/child/tasks"><span class="nav-icon">&bull;</span><span>Tareas</span></a><a id="domus-points-link" class="sidebar-link" href="/account/domus-points"><span class="nav-icon">&bull;</span><span>Puntos Domus</span></a><a class="sidebar-link" href="/account/education"><span class="nav-icon">&bull;</span><span>Educacion</span></a>
            </nav>
            <div id="scroll-hint" class="scroll-hint">Desliza para ver mas</div>
        </div>
    </aside>

    <section class="page content card">
        <div class="top-row"><button id="menu-btn" class="btn blue-btn menu-toggle" type="button">Menu</button><button id="logout-btn" class="btn btn-inline gold-btn right" type="button">Cerrar sesion</button></div>
        <p class="brand mt-2">DOMUS</p><h1 id="greeting">Hola</h1><p class="subtitle">Aqui tienes un resumen general de tu hogar financiero.</p>
        <section class="stats-grid mt-2">
            <article class="stat-card stat-card-blue"><p id="primary-money-title" class="stat-title">Dinero usado</p><p id="available-balance" class="stat-value">$0.00</p><p id="primary-money-note" class="stat-note">Entregado y comprometido</p><button id="add-money-btn" class="btn gold-btn mt-1 is-hidden" type="button">Agregar dinero</button></article>
            <article class="stat-card stat-card-gold"><p id="stat-2-title" class="stat-title">Prestamos</p><p id="stat-2-value" class="stat-value">$0.00</p><p id="stat-2-note" class="stat-note">Capital recuperado: $0.00<br>Capital por recuperar: $0.00</p></article>
            <article class="stat-card stat-card-mint"><p id="stat-3-title" class="stat-title">Intereses generados</p><p id="stat-3-value" class="stat-value">$0.00</p><p id="stat-3-note" class="stat-note">Este mes</p></article>
            <article id="domus-points-card" class="stat-card stat-card-lilac is-hidden"><p class="stat-title">Puntos DOMUS</p><p id="domus-points-value" class="stat-value">0</p><p id="domus-points-note" class="stat-note">Sin nivel</p></article>
        </section>
        <section id="users-summary-card" class="quick-card notifications-card mt-2 is-hidden">
            <p class="quick-card-title">Resumen de usuarios</p>
            <div class="users-summary-table-wrap">
                <table class="users-summary-table">
                    <thead>
                        <tr>
                            <th>Usuario</th>
                            <th>Saldo</th>
                            <th>Deuda</th>
                            <th>Estado</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody id="users-summary-body">
                        <tr><td colspan="5" class="users-summary-empty">Cargando usuarios...</td></tr>
                    </tbody>
                </table>
            </div>
        </section>
        <section id="loans-distribution-card" class="quick-card notifications-card mt-2 is-hidden is-loading">
            <p class="quick-card-title">Distribucion de deuda</p>
            <div id="loans-distribution-layout" class="loans-distribution-layout">
                <div id="loans-distribution-chart-wrap" class="loans-distribution-chart-wrap">
                    <canvas id="loans-distribution-chart" aria-label="Distribucion de deuda por usuario"></canvas>
                </div>
                <div id="loans-distribution-table-wrap" class="users-summary-table-wrap">
                    <table class="users-summary-table loans-distribution-table">
                        <thead>
                            <tr>
                                <th>Nombre</th>
                                <th>%</th>
                                <th>Deuda</th>
                            </tr>
                        </thead>
                        <tbody id="loans-distribution-body">
                            <tr><td colspan="3" class="users-summary-empty">Cargando distribucion...</td></tr>
                        </tbody>
                    </table>
                </div>
            </div>
            <div id="loans-distribution-empty" class="loans-distribution-empty is-loading">Cargando distribucion...</div>
        </section>
        <section id="notifications-card" class="quick-card notifications-card mt-2">
            <p class="quick-card-title">Ultimos movimientos</p>
            <div id="notifications-list" class="notifications-list"><p class="notification-empty">Cargando movimientos...</p></div>
        </section>
        <section id="new-loan-card" class="quick-card mt-2">
            <p class="quick-card-title">Nuevo prestamo</p>
            <p class="quick-card-subtitle">Otorga un prestamo o credito a un miembro de tu familia.</p>
            <a id="new-loan-link" class="btn gold-btn btn-inline quick-card-action" href="/parent/loans">Nuevo prestamo</a>
        </section>
        <pre id="output" class="result mt-2">Cargando...</pre>
    </section>
</main>

<div id="money-modal" class="modal-overlay">
    <section class="modal-card"><div class="top-row"><h2 class="modal-title">Agregar dinero</h2><button id="money-modal-close" class="sidebar-close modal-close" type="button">x</button></div><p class="subtitle">Ingresa un monto en pesos, con hasta 2 decimales.</p><form id="money-form" class="form"><div class="field"><label for="money-amount">Monto</label><input id="money-amount" class="input" type="text" inputmode="decimal" placeholder="14.12" required></div><div class="modal-actions mt-2"><button id="money-cancel" class="btn blue-btn btn-inline" type="button">Cancelar</button><button class="btn gold-btn btn-inline" type="submit">Guardar</button></div></form></section>
</div>

<script>
const API_BASE='/api',TOKEN_KEY='parent_auth_token';
const greeting=document.getElementById('greeting'),output=document.getElementById('output'),availableBalance=document.getElementById('available-balance'),primaryMoneyTitle=document.getElementById('primary-money-title'),primaryMoneyNote=document.getElementById('primary-money-note'),addMoneyButton=document.getElementById('add-money-btn'),logoutButton=document.getElementById('logout-btn'),menuButton=document.getElementById('menu-btn'),sidebar=document.getElementById('sidebar'),sidebarUserName=document.getElementById('sidebar-user-name'),sidebarUserLevel=document.getElementById('sidebar-user-level'),sidebarClose=document.getElementById('sidebar-close'),sidebarOverlay=document.getElementById('sidebar-overlay'),sidebarScroll=document.getElementById('sidebar-scroll'),scrollHint=document.getElementById('scroll-hint'),moneyModal=document.getElementById('money-modal'),moneyForm=document.getElementById('money-form'),moneyAmountInput=document.getElementById('money-amount'),moneyModalClose=document.getElementById('money-modal-close'),moneyCancel=document.getElementById('money-cancel'),stat2Title=document.getElementById('stat-2-title'),stat2Value=document.getElementById('stat-2-value'),stat2Note=document.getElementById('stat-2-note'),stat3Title=document.getElementById('stat-3-title'),stat3Value=document.getElementById('stat-3-value'),stat3Note=document.getElementById('stat-3-note'),domusPointsCard=document.getElementById('domus-points-card'),domusPointsValue=document.getElementById('domus-points-value'),domusPointsNote=document.getElementById('domus-points-note'),newLoanCard=document.getElementById('new-loan-card'),tasksLink=document.getElementById('tasks-link'),loansLink=document.getElementById('loans-link'),transfersLink=document.getElementById('transfers-link'),allowancesLink=document.getElementById('allowances-link'),savingsBoxesLink=document.getElementById('savings-boxes-link'),goalsLink=document.getElementById('goals-link'),domusPointsLink=document.getElementById('domus-points-link'),newLoanLink=document.getElementById('new-loan-link'),notificationsList=document.getElementById('notifications-list'),usersSummaryCard=document.getElementById('users-summary-card'),usersSummaryBody=document.getElementById('users-summary-body'),loansDistributionCard=document.getElementById('loans-distribution-card'),loansDistributionBody=document.getElementById('loans-distribution-body'),loansDistributionChartCanvas=document.getElementById('loans-distribution-chart');
const loansDistributionLayout=document.getElementById('loans-distribution-layout'),loansDistributionChartWrap=document.getElementById('loans-distribution-chart-wrap'),loansDistributionTableWrap=document.getElementById('loans-distribution-table-wrap'),loansDistributionEmpty=document.getElementById('loans-distribution-empty');
let loansDistributionChart=null;
function getToken(){return localStorage.getItem(TOKEN_KEY);} function clearToken(){localStorage.removeItem(TOKEN_KEY);} function openSidebar(){sidebar.classList.add('is-open');sidebarOverlay.classList.add('is-open');} function closeSidebar(){sidebar.classList.remove('is-open');sidebarOverlay.classList.remove('is-open');}
function openMoneyModal(){moneyModal.classList.add('is-open');moneyAmountInput.value='';setTimeout(()=>moneyAmountInput.focus(),10);} function closeMoneyModal(){moneyModal.classList.remove('is-open');}
function updateScrollHint(){const canScroll=sidebarScroll.scrollHeight>sidebarScroll.clientHeight;const nearBottom=sidebarScroll.scrollTop+sidebarScroll.clientHeight>=sidebarScroll.scrollHeight-4;scrollHint.classList.toggle('is-visible',canScroll&&!nearBottom);} 
function escapeHtml(value){return String(value??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}
function toMoneyFromCents(value){const amount=Number(value||0)/100;return '$'+amount.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});}
function parseMoneyToCents(value){const normalized=String(value??'').trim().replace(',', '.');if(!/^\d+(?:\.\d{1,2})?$/.test(normalized)){return null;}const parts=normalized.split('.');const whole=Number(parts[0]||0);const fraction=String(parts[1]||'').padEnd(2,'0').slice(0,2);return (whole*100)+Number(fraction);}
async function apiRequest(path,method,payload){const token=getToken();const headers={Accept:'application/json','Content-Type':'application/json'};if(token){headers.Authorization='Bearer '+token;}const response=await fetch(API_BASE+path,{method,headers,body:payload?JSON.stringify(payload):undefined});const data=await response.json().catch(()=>({}));if(!response.ok){throw {status:response.status,data};}return data;}
function notificationClass(category){const slug=String(category||'general').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')||'general';return 'notification-category-'+slug;}
function formatNotificationDate(value){if(!value){return '';}const date=new Date(value);if(Number.isNaN(date.getTime())){return '';}return date.toLocaleDateString('es-MX',{day:'2-digit',month:'short'})+' '+date.toLocaleTimeString('es-MX',{hour:'2-digit',minute:'2-digit'});}
function toMoney(value){return '$'+Number(value||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});}
function healthBadgeClass(key){if(key==='overdue'){return 'loan-health-badge loan-health-badge-overdue';}if(key==='due-soon'){return 'loan-health-badge loan-health-badge-due-soon';}return 'loan-health-badge loan-health-badge-current';}
function renderUsersSummary(items){if(!usersSummaryBody){return;}if(!items.length){usersSummaryBody.innerHTML='<tr><td colspan="5" class="users-summary-empty">Todavia no has creado usuarios.</td></tr>';return;}usersSummaryBody.innerHTML=items.map(item=>'<tr><td><div class="users-summary-user"><p class="users-summary-name">'+escapeHtml(item.name||'Usuario')+'</p><p class="users-summary-level">'+escapeHtml(item.level_label||'Sin nivel')+'</p></div></td><td>'+escapeHtml(item.balance_display||'$0.00')+'</td><td>'+escapeHtml(item.debt_principal_display||'$0.00')+'</td><td><span class="'+healthBadgeClass(item.loan_health?.key)+'">'+escapeHtml(item.loan_health?.label||'Al dia')+'</span></td><td class="users-summary-action-cell"><a class="users-summary-action" href="/parent/users/'+Number(item.user_id||0)+'">&gt;</a></td></tr>').join('');}
function buildLoansDistribution(loans){const grouped=new Map();(Array.isArray(loans)?loans:[]).forEach(loan=>{const name=loan?.child?.name||'Usuario';const remainingCents=Number(loan?.payment_summary?.remaining_principal_cents||0);if(remainingCents<=0){return;}grouped.set(name,(grouped.get(name)||0)+remainingCents);});const items=Array.from(grouped.entries()).map(([name,debtCents])=>({name,debtCents})).sort((a,b)=>b.debtCents-a.debtCents);const totalCents=items.reduce((sum,item)=>sum+item.debtCents,0);return items.map(item=>({...item,percentage:totalCents>0?(item.debtCents/totalCents)*100:0}));}
function chartPalette(index){const colors=['#0b2a77','#d6a645','#16a34a','#0ea5e9','#dc2626','#7c3aed','#ea580c','#475569'];return colors[index%colors.length];}
function setLoansDistributionLoading(){if(!loansDistributionBody||!loansDistributionChartWrap||!loansDistributionTableWrap||!loansDistributionEmpty){return;}loansDistributionCard?.classList.add('is-loading');loansDistributionCard?.classList.remove('is-empty');loansDistributionChartWrap.classList.add('is-hidden');loansDistributionTableWrap.classList.add('is-hidden');loansDistributionEmpty.classList.remove('is-hidden');loansDistributionEmpty.classList.add('is-loading');loansDistributionEmpty.textContent='Cargando distribucion...';loansDistributionBody.innerHTML='';if(loansDistributionChart){loansDistributionChart.destroy();loansDistributionChart=null;}}
function renderLoansDistribution(loans){if(!loansDistributionBody||!loansDistributionChartWrap||!loansDistributionTableWrap||!loansDistributionEmpty){return;}loansDistributionCard?.classList.remove('is-loading');loansDistributionEmpty.classList.remove('is-loading');const items=buildLoansDistribution(loans);if(!items.length){loansDistributionCard?.classList.add('is-empty');loansDistributionChartWrap.classList.add('is-hidden');loansDistributionTableWrap.classList.add('is-hidden');loansDistributionEmpty.classList.remove('is-hidden');loansDistributionEmpty.textContent='No hay deuda activa por mostrar.';loansDistributionBody.innerHTML='';if(loansDistributionChart){loansDistributionChart.destroy();loansDistributionChart=null;}return;}loansDistributionCard?.classList.remove('is-empty');loansDistributionChartWrap.classList.remove('is-hidden');loansDistributionTableWrap.classList.remove('is-hidden');loansDistributionEmpty.classList.add('is-hidden');loansDistributionBody.innerHTML=items.map(item=>'<tr><td>'+escapeHtml(item.name)+'</td><td>'+item.percentage.toFixed(1)+'%</td><td>'+toMoneyFromCents(item.debtCents)+'</td></tr>').join('');if(typeof Chart==='undefined'||!loansDistributionChartCanvas){return;}const labels=items.map(item=>item.name);const values=items.map(item=>Number((item.debtCents/100).toFixed(2)));const colors=items.map((_,index)=>chartPalette(index));if(loansDistributionChart){loansDistributionChart.destroy();}loansDistributionChart=new Chart(loansDistributionChartCanvas,{type:'pie',data:{labels,datasets:[{data:values,backgroundColor:colors,borderColor:'#ffffff',borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{boxWidth:12,color:'#0f172a'}},tooltip:{callbacks:{label(context){const value=Number(context.parsed||0);const total=values.reduce((sum,item)=>sum+item,0);const percentage=total>0?(value/total)*100:0;return context.label+': '+toMoney(value)+' ('+percentage.toFixed(1)+'%)';}}}}}});}
async function loadParentUsersSummary(){if(!usersSummaryCard||!usersSummaryBody){return;}try{const response=await apiRequest('/family-members-summary','GET');renderUsersSummary(response.members||[]);}catch(_error){usersSummaryBody.innerHTML='<tr><td colspan="5" class="users-summary-empty">No se pudo cargar el resumen de usuarios.</td></tr>';}}
function renderNotifications(items){if(!items.length){notificationsList.innerHTML='<p class="notification-empty">Aun no hay movimientos recientes.</p>';return;}notificationsList.innerHTML=items.map(item=>'<article class="notification-item '+notificationClass(item.category)+'"><div class="notification-top"><span class="notification-category">'+escapeHtml(item.category||'general')+'</span><time class="notification-time">'+escapeHtml(formatNotificationDate(item.created_at))+'</time></div><p class="notification-text">'+escapeHtml(item.text||'Movimiento registrado.')+'</p></article>').join('');}
async function loadNotifications(){try{const response=await apiRequest('/notifications?limit=6','GET');renderNotifications(response.notifications||[]);}catch(error){notificationsList.innerHTML='<p class="notification-empty">No se pudieron cargar los movimientos.</p>';}}
async function loadSidebarLevel(){try{const points=await apiRequest('/child/domus-points','GET');const level=points.level;sidebarUserLevel.style.display='block';sidebarUserLevel.textContent=level?('Nivel '+Number(level.level_number||1)+' - '+level.name):'Sin nivel';}catch(_error){sidebarUserLevel.style.display='block';sidebarUserLevel.textContent='Sin nivel';}}
function formatLevelLabel(level){return level?('Nivel '+Number(level.level_number||1)+' - '+(level.name||'Sin nombre')):'Sin nivel';}
async function loadUser(){if(!getToken()){window.location.href='/login';return;}try{const data=await apiRequest('/me','GET');const name=data.user?.name||'';const role=data.user?.role||'parent';const loansUrl=role==='parent'?'/parent/loans':'/member/loans';if(tasksLink){tasksLink.href=(role==='parent'?'/parent/tasks':'/child/tasks');}if(loansLink){loansLink.href=loansUrl;}if(transfersLink){transfersLink.href='/parent/transfers';transfersLink.classList.toggle('is-hidden',role!=='parent');}if(allowancesLink){allowancesLink.href='/parent/allowances';allowancesLink.classList.toggle('is-hidden',role!=='parent');}if(savingsBoxesLink){savingsBoxesLink.href=(role==='parent'?'/parent/savings-boxes':'/child/savings-boxes');savingsBoxesLink.classList.toggle('is-hidden',false);}if(goalsLink){goalsLink.href='/child/goals';goalsLink.classList.toggle('is-hidden',role==='parent');}if(domusPointsLink){domusPointsLink.href=(role==='parent'?'/parent/domus-points':'/child/domus-points');}if(newLoanLink){newLoanLink.href=loansUrl;}const balanceAmount=Number(data.user?.balance_cents||0);greeting.textContent='Hola '+name;sidebarUserName.textContent=name||'Usuario';availableBalance.textContent=data.user?.balance_display||toMoneyFromCents(balanceAmount);if(role==='parent'){primaryMoneyTitle.textContent='Dinero usado';primaryMoneyNote.textContent='Entregado y comprometido';addMoneyButton.classList.add('is-hidden');}else{primaryMoneyTitle.textContent='Dinero disponible';primaryMoneyNote.textContent='Disponible en caja';addMoneyButton.classList.remove('is-hidden');}if(role==='child'||role==='member'){sidebarUserLevel.style.display='block';await loadSidebarLevel();stat2Title.textContent='Deuda total';stat2Value.textContent='$1,150.00';stat2Note.textContent='En 2 prestamos';stat3Title.textContent='Ahorros totales';stat3Value.textContent='$980.00';stat3Note.textContent='Sigue creciendo';domusPointsCard.classList.remove('is-hidden');newLoanCard.classList.add('is-hidden');usersSummaryCard.classList.add('is-hidden');loansDistributionCard.classList.add('is-hidden');}else{sidebarUserLevel.style.display='none';stat2Title.textContent='Total prestado';usersSummaryCard.classList.remove('is-hidden');loansDistributionCard.classList.remove('is-hidden');setLoansDistributionLoading();try{const [activeTotals,loansResponse,usersSummaryResponse]=await Promise.all([apiRequest('/loans/active-total','GET'),apiRequest('/loans','GET'),apiRequest('/family-members-summary','GET')]);const loans=Array.isArray(loansResponse.loans)?loansResponse.loans:[];const activeLoans=loans.filter(loan=>['approved','paid'].includes(String(loan.status||'').toLowerCase()));const interestThisMonth=Number(activeTotals.interest_generated_this_month||0);const totalLoaned=activeLoans.reduce((sum,loan)=>sum+Number(loan.amount||0),0);const recoveredPrincipal=activeLoans.reduce((sum,loan)=>sum+(Number(loan.payment_summary?.paid_principal_cents||0)/100),0);const remainingPrincipal=Math.max(totalLoaned-recoveredPrincipal,0);stat2Value.textContent=toMoney(totalLoaned);stat2Note.innerHTML='Capital recuperado: '+toMoney(recoveredPrincipal)+'<br>Capital por recuperar: '+toMoney(remainingPrincipal);stat3Title.textContent='Intereses generados';stat3Value.textContent=toMoney(interestThisMonth);stat3Note.textContent='Este mes';renderUsersSummary(usersSummaryResponse.members||[]);renderLoansDistribution(activeLoans);}catch(_e){stat2Value.textContent='$0.00';stat2Note.innerHTML='Capital recuperado: $0.00<br>Capital por recuperar: $0.00';stat3Title.textContent='Intereses generados';stat3Value.textContent='$0.00';stat3Note.textContent='Este mes';usersSummaryBody.innerHTML='<tr><td colspan="5" class="users-summary-empty">No se pudo cargar el resumen de usuarios.</td></tr>';if(loansDistributionEmpty){loansDistributionEmpty.classList.remove('is-loading');loansDistributionEmpty.classList.remove('is-hidden');loansDistributionEmpty.textContent='No se pudo cargar la distribucion.';}loansDistributionBody.innerHTML='';if(loansDistributionChartWrap){loansDistributionChartWrap.classList.add('is-hidden');}if(loansDistributionTableWrap){loansDistributionTableWrap.classList.add('is-hidden');}if(loansDistributionChart){loansDistributionChart.destroy();loansDistributionChart=null;}}domusPointsCard.classList.add('is-hidden');newLoanCard.classList.remove('is-hidden');}await loadNotifications();output.textContent=JSON.stringify(data,null,2);}catch(error){output.textContent=JSON.stringify(error,null,2);if(error.status===401){clearToken();window.location.href='/login';}}}
async function loadUser(){if(!getToken()){window.location.href='/login';return;}try{const data=await apiRequest('/me','GET');const name=data.user?.name||'';const role=data.user?.role||'parent';const loansUrl=role==='parent'?'/parent/loans':'/member/loans';if(tasksLink){tasksLink.href=(role==='parent'?'/parent/tasks':'/child/tasks');}if(loansLink){loansLink.href=loansUrl;}if(transfersLink){transfersLink.href='/parent/transfers';transfersLink.classList.toggle('is-hidden',role!=='parent');}if(allowancesLink){allowancesLink.href='/parent/allowances';allowancesLink.classList.toggle('is-hidden',role!=='parent');}if(savingsBoxesLink){savingsBoxesLink.href=(role==='parent'?'/parent/savings-boxes':'/child/savings-boxes');savingsBoxesLink.classList.toggle('is-hidden',false);}if(goalsLink){goalsLink.href='/child/goals';goalsLink.classList.toggle('is-hidden',role==='parent');}if(domusPointsLink){domusPointsLink.href=(role==='parent'?'/parent/domus-points':'/child/domus-points');}if(newLoanLink){newLoanLink.href=loansUrl;}const balanceAmount=Number(data.user?.balance_cents||0);greeting.textContent='Hola '+name;sidebarUserName.textContent=name||'Usuario';availableBalance.textContent=data.user?.balance_display||toMoneyFromCents(balanceAmount);if(role==='parent'){primaryMoneyTitle.textContent='Dinero usado';primaryMoneyNote.textContent='Entregado y comprometido';addMoneyButton.classList.add('is-hidden');}else{primaryMoneyTitle.textContent='Dinero disponible';primaryMoneyNote.textContent='Disponible en caja';addMoneyButton.classList.remove('is-hidden');}if(role==='child'||role==='member'){stat2Title.textContent='Deuda total';stat3Title.textContent='Ahorros totales';domusPointsCard.classList.remove('is-hidden');newLoanCard.classList.add('is-hidden');usersSummaryCard.classList.add('is-hidden');loansDistributionCard.classList.add('is-hidden');try{const [pointsResponse,loansResponse,savingsBoxesResponse,goalsResponse]=await Promise.all([apiRequest('/child/domus-points','GET'),apiRequest('/member/loans','GET'),apiRequest('/savings-boxes','GET'),apiRequest('/child/goals','GET')]);const levelLabel=formatLevelLabel(pointsResponse.level);sidebarUserLevel.style.display='block';sidebarUserLevel.textContent=levelLabel;const loans=Array.isArray(loansResponse.loans)?loansResponse.loans:[];const remainingDebt=loans.reduce((sum,loan)=>sum+Number(loan?.payment_summary?.remaining_principal_cents||0),0)/100;const activeLoanCount=loans.filter(loan=>Number(loan?.payment_summary?.remaining_principal_cents||0)>0).length;const savingsBoxes=Array.isArray(savingsBoxesResponse.savings_boxes)?savingsBoxesResponse.savings_boxes:[];const savingsBoxesTotal=savingsBoxes.reduce((sum,box)=>sum+(Array.isArray(box?.accounts)?box.accounts.reduce((accountSum,account)=>accountSum+Number(account?.principal_cents||0)+Number(account?.earned_interest_cents||0),0):0),0)/100;const goals=Array.isArray(goalsResponse.goals)?goalsResponse.goals:[];const goalsTotal=goals.reduce((sum,goal)=>sum+Number(goal?.saved_amount_cents||0),0)/100;const totalSavings=(balanceAmount/100)+savingsBoxesTotal+goalsTotal;const availableDomusPoints=Number(pointsResponse?.points?.available||0);stat2Value.textContent=toMoney(remainingDebt);stat2Note.textContent='En '+activeLoanCount+' prestamo'+(activeLoanCount===1?'':'s');stat3Value.textContent=toMoney(totalSavings);stat3Note.textContent='Saldo + cajas + metas';if(domusPointsValue){domusPointsValue.textContent=availableDomusPoints.toLocaleString('en-US');}if(domusPointsNote){domusPointsNote.textContent=levelLabel;}}catch(_childError){sidebarUserLevel.style.display='block';sidebarUserLevel.textContent='Sin nivel';stat2Value.textContent='$0.00';stat2Note.textContent='En 0 prestamos';stat3Value.textContent=toMoney(balanceAmount/100);stat3Note.textContent='Saldo + cajas + metas';if(domusPointsValue){domusPointsValue.textContent='0';}if(domusPointsNote){domusPointsNote.textContent='Sin nivel';}}}else{sidebarUserLevel.style.display='none';stat2Title.textContent='Total prestado';usersSummaryCard.classList.remove('is-hidden');loansDistributionCard.classList.remove('is-hidden');setLoansDistributionLoading();try{const [activeTotals,loansResponse,usersSummaryResponse]=await Promise.all([apiRequest('/loans/active-total','GET'),apiRequest('/loans','GET'),apiRequest('/family-members-summary','GET')]);const loans=Array.isArray(loansResponse.loans)?loansResponse.loans:[];const activeLoans=loans.filter(loan=>['approved','paid'].includes(String(loan.status||'').toLowerCase()));const interestThisMonth=Number(activeTotals.interest_generated_this_month||0);const totalLoaned=activeLoans.reduce((sum,loan)=>sum+Number(loan.amount||0),0);const recoveredPrincipal=activeLoans.reduce((sum,loan)=>sum+(Number(loan.payment_summary?.paid_principal_cents||0)/100),0);const remainingPrincipal=Math.max(totalLoaned-recoveredPrincipal,0);stat2Value.textContent=toMoney(totalLoaned);stat2Note.innerHTML='Capital recuperado: '+toMoney(recoveredPrincipal)+'<br>Capital por recuperar: '+toMoney(remainingPrincipal);stat3Title.textContent='Intereses generados';stat3Value.textContent=toMoney(interestThisMonth);stat3Note.textContent='Este mes';renderUsersSummary(usersSummaryResponse.members||[]);renderLoansDistribution(activeLoans);}catch(_e){stat2Value.textContent='$0.00';stat2Note.innerHTML='Capital recuperado: $0.00<br>Capital por recuperar: $0.00';stat3Title.textContent='Intereses generados';stat3Value.textContent='$0.00';stat3Note.textContent='Este mes';usersSummaryBody.innerHTML='<tr><td colspan="5" class="users-summary-empty">No se pudo cargar el resumen de usuarios.</td></tr>';if(loansDistributionEmpty){loansDistributionEmpty.classList.remove('is-loading');loansDistributionEmpty.classList.remove('is-hidden');loansDistributionEmpty.textContent='No se pudo cargar la distribucion.';}loansDistributionBody.innerHTML='';if(loansDistributionChartWrap){loansDistributionChartWrap.classList.add('is-hidden');}if(loansDistributionTableWrap){loansDistributionTableWrap.classList.add('is-hidden');}if(loansDistributionChart){loansDistributionChart.destroy();loansDistributionChart=null;}}domusPointsCard.classList.add('is-hidden');newLoanCard.classList.remove('is-hidden');}await loadNotifications();output.textContent=JSON.stringify(data,null,2);}catch(error){output.textContent=JSON.stringify(error,null,2);if(error.status===401){clearToken();window.location.href='/login';}}}
logoutButton.addEventListener('click',async()=>{try{await apiRequest('/logout','POST');}catch(e){}finally{clearToken();window.location.href='/login';}});
menuButton.addEventListener('click',()=>{if(sidebar.classList.contains('is-open')){closeSidebar();return;}openSidebar();updateScrollHint();}); sidebarClose.addEventListener('click',closeSidebar); sidebarOverlay.addEventListener('click',closeSidebar); sidebarScroll.addEventListener('scroll',updateScrollHint);
addMoneyButton.addEventListener('click',openMoneyModal); moneyModalClose.addEventListener('click',closeMoneyModal); moneyCancel.addEventListener('click',closeMoneyModal); moneyModal.addEventListener('click',e=>{if(e.target===moneyModal){closeMoneyModal();}});
moneyForm.addEventListener('submit',async e=>{e.preventDefault();const amountCents=parseMoneyToCents(moneyAmountInput.value);if(amountCents===null||amountCents<1){output.textContent=JSON.stringify({message:'Escribe un monto valido con hasta 2 decimales.'},null,2);return;}try{const response=await apiRequest('/balance/add','POST',{amount:moneyAmountInput.value.trim()});const newBalance=Number(response.data.balance);availableBalance.textContent=toMoneyFromCents(newBalance);output.textContent=JSON.stringify(response,null,2);if(window.handleDomusAchievements){window.handleDomusAchievements(response.achievements);}await loadNotifications();closeMoneyModal();}catch(error){output.textContent=JSON.stringify(error,null,2);}});
window.addEventListener('resize',()=>{if(window.innerWidth>=768){closeSidebar();}updateScrollHint();}); updateScrollHint(); loadUser();
</script>
